"use client";

import { useStore } from "@/store";

const MONO: React.CSSProperties = {
  fontFamily: "var(--font-sans)",
  fontSize: 13,
  letterSpacing: "-0.01em",
  lineHeight: 1.1,
  color: "#141412",
};

const SERIF: React.CSSProperties = {
  fontFamily: "var(--font-serif)",
  lineHeight: 1.15,
};

// ── Counter badge — hangs from top of viewport ────────────────────────────────
function CounterBadge({ index, total }: { index: number; total: number }) {
  const displayIdx = total > 0 ? index + 1 : 0;
  const W = 52, H = 98;
  const bodyH = H * 0.82;
  return (
    <div style={{ position: "relative", width: W, height: H, flexShrink: 0 }}>
      <svg
        width={W} height={H}
        viewBox="0 0 61 115"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        style={{ position: "absolute", top: 0, left: 0 }}
      >
        <path
          d="M0 106.834V3.38235C0 1.51433 1.51433 0 3.38235 0H57.5C59.368 0 60.8824 1.51433 60.8824 3.38236V106.834C60.8824 109.848 57.2391 111.357 55.1083 109.226L32.8329 86.9505C31.512 85.6296 29.3704 85.6296 28.0495 86.9505L5.77404 109.226C3.64327 111.357 0 109.848 0 106.834Z"
          fill="#141412"
        />
      </svg>
      <div style={{
        position: "absolute", top: 0, left: 0,
        width: W, height: bodyH,
        display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center", gap: 1,
      }}>
        <span style={{ ...SERIF, fontSize: 13, color: "#e9eae5", lineHeight: 1, userSelect: "none" }}>
          {displayIdx}
        </span>
        <span style={{ ...MONO, fontSize: 8, color: "#e9eae5", opacity: 0.4, lineHeight: 1, userSelect: "none" }}>
          //
        </span>
        <span style={{ ...SERIF, fontSize: 11, color: "#e9eae5", opacity: 0.65, lineHeight: 1, userSelect: "none" }}>
          {total}
        </span>
      </div>
    </div>
  );
}

