export function FilterBar() {
  const { activeView, setActiveView, shelfScrollIndex, books } = useStore();

  const views = [
    { id: 'shelf' as const,  label: 'SHELF',      icon: <ShelfIcon /> },
    { id: 'index' as const,  label: 'FULL INDEX', icon: <IndexIcon /> },
    { id: 'data'  as const,  label: 'DATA',       icon: <DataIcon /> },
  ];

  return (
    <div style={{
      position: "fixed",
      top: 20,
      left: 20,
      zIndex: 30,
      display: "flex",
      flexDirection: "row",
      alignItems: "flex-start",
      gap: 12,
    }}>
      {/* BB logotype — standalone mark */}
      <BBLogo />

      {/* Counter badge — hangs from top, right after BB logo */}
      <CounterBadge index={shelfScrollIndex} total={books.length} />

      {/* Hairline divider */}
      <div style={{ width: 1, height: 20, background: "#14141230", flexShrink: 0 }} />

      {/* View switcher — horizontal */}
      {views.map(({ id, label, icon }) => {
        const active = activeView === id;
        return (
          <button
            key={id}
            onClick={() => setActiveView(id)}
            style={{
              ...MONO,
              display: "flex",
              alignItems: "center",
              gap: 6,
              padding: "4px 8px",
              border: active ? "1px solid #696969" : "1px solid transparent",
              borderRadius: 8,
              background: "none",
              cursor: "pointer",
              opacity: active ? 1 : 0.5,
              transition: "opacity 0.15s, border-color 0.15s",
            }}
          >
            {icon}
            {label}
          </button>
        );
      })}
    </div>
  );
}
